package src.blocks.tour.org.apache.cocoon.samples.tour.beans;

public class TaskBean { private String m_taskName ; private String m_assignedTo ; private final int m_id ; private final LinkedList m_comments = new LinkedList ( ) ; public static int m_idCounter ; public TaskBean ( ) { synchronized ( TaskBean . class ) { m_id = ++ m_idCounter ; } } public String toString ( ) { final StringBuffer sb = new StringBuffer ( ) ; sb . append ( "TaskBean #" + m_id + " (" + m_taskName + "," + m_assignedTo + ")" ) ; for ( Iterator it = m_comments . iterator ( ) ; it . hasNext ( ) ; ) { sb . append ( "\n\t" ) ; sb . append ( it . next ( ) ) ; } return sb . toString ( ) ; } public int getId ( ) { return m_id ; } public String getTaskName ( ) { return m_taskName ; } public void setTaskName ( String m_taskName ) { this . m_taskName = m_taskName ; } public String getAssignedTo ( ) { return m_assignedTo ; } public void setAssignedTo ( String m_assignedTo ) { this . m_assignedTo = m_assignedTo ; } public List getComments ( ) { return m_comments ; } public void setComments ( List c ) { m_comments . clear ( ) ; Collections . copy ( m_comments , c ) ; } public void addComment ( TaskCommentBean tcb ) { m_comments . add ( tcb ) ; } }